@app.route('/submit_bid/<int:auction_id>', methods=['POST'])
def submit_bid(auction_id):
    auctions = read_auctions()
    bids = read_bids()
    histories = read_bid_history()

    auction = next((a for a in auctions if a['auction_id'] == auction_id), None)
    if auction is None:
        return redirect(url_for('auction_catalog'))

    bidder_name = request.form.get('bidder_name', '').strip()
    try:
        bid_amount = float(request.form.get('bid_amount', '0').strip())
    except ValueError:
        bid_amount = 0.0

    # Minimum bid must be greater than current_bid
    current_bid = auction['current_bid'] if auction['current_bid'] > 0 else auction['starting_bid']
    if not bidder_name or bid_amount <= current_bid:
        # Prepare error message and re-render place_bid.html
        auction_name = auction['item_name']
        minimum_bid = current_bid
        error_message = 'Invalid bid: Please enter a valid name and a bid amount higher than the current bid.'
        return render_template('place_bid.html', auction_name=auction_name, minimum_bid=minimum_bid, error_message=error_message)

    # Create new bid_id, history_id
    new_bid_id = max([b['bid_id'] for b in bids], default=0) + 1
    new_history_id = max([h['history_id'] for h in histories], default=0) + 1

    # Use current timestamp for bid_timestamp
    bid_timestamp = datetime.now().strftime('%Y-%m-%d %H:%M')

    # Append new bid
    new_bid = {
        'bid_id': new_bid_id,
        'auction_id': auction_id,
        'bidder_name': bidder_name,
        'bid_amount': bid_amount,
        'bid_timestamp': bid_timestamp
    }
    bids.append(new_bid)
    write_bids(bids)

    # Append new history
    new_history = {
        'history_id': new_history_id,
        'auction_id': auction_id,
        'auction_name': auction['item_name'],
        'bidder_name': bidder_name,
        'bid_amount': bid_amount,
        'bid_timestamp': bid_timestamp
    }
    histories.append(new_history)
    path_history = os.path.join(data_dir, 'bid_history.txt')
    with open(path_history, 'w', encoding='utf-8') as f:
        for h in histories:
            f.write(f"{h['history_id']}|{h['auction_id']}|{h['auction_name']}|{h['bidder_name']}|{h['bid_amount']}|{h['bid_timestamp']}\n")

    # Update auction current_bid
    for a in auctions:
        if a['auction_id'] == auction_id:
            a['current_bid'] = bid_amount
            break
    write_auctions(auctions)

    return redirect(url_for('auction_details', auction_id=auction_id))


