from flask import Flask, render_template, redirect, url_for, request
from datetime import datetime
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions for file read/write and parsing

def read_books():
    books = []
    path = os.path.join(DATA_DIR, 'books.txt')
    if not os.path.isfile(path):
        return books
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 8:
                continue
            try:
                book = {
                    'book_id': int(parts[0]),
                    'title': parts[1],
                    'author': parts[2],
                    'isbn': parts[3],
                    'category': parts[4],
                    'price': float(parts[5]),
                    'stock': int(parts[6]),
                    'description': parts[7]
                }
                books.append(book)
            except:
                continue
    return books


def read_categories():
    categories = []
    path = os.path.join(DATA_DIR, 'categories.txt')
    if not os.path.isfile(path):
        return categories
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) !=3:
                continue
            try:
                # category_id = int(parts[0]) unused
                category_name = parts[1]
                categories.append(category_name)
            except:
                continue
    return categories


def read_cart():
    cart = []
    path = os.path.join(DATA_DIR, 'cart.txt')
    if not os.path.isfile(path):
        return cart
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) !=4:
                continue
            try:
                item = {
                    'item_id': int(parts[0]),  # cart_id
                    'book_id': int(parts[1]),
                    'quantity': int(parts[2]),
                    'added_date': parts[3]
                }
                cart.append(item)
            except:
                continue
    return cart


def write_cart(cart):
    path = os.path.join(DATA_DIR, 'cart.txt')
    lines = []
    for item in cart:
        # cart_id|book_id|quantity|added_date
        line = f"{item['item_id']}|{item['book_id']}|{item['quantity']}|{item['added_date']}"
        lines.append(line)
    content = '\n'.join(lines)
    return content


def read_orders():
