    return applications


def read_resumes():
    resumes = []
    try:
        with open(os.path.join(DATA_DIR, 'resumes.txt'), encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                resume = {
                    'resume_id': int(parts[0]),
