    return resumes


def write_resumes(resumes):
    lines = []
    for r in resumes:
        line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
        lines.append(line)
    with open(os.path.join(DATA_DIR, 'resumes.txt'), 'w', encoding='utf-8') as f:
