from flask import Flask, render_template, redirect, url_for, request
from datetime import datetime
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper Functions -----------------------------------------------------------------
DATA_DIR = 'data'

# Load users data from users.txt
# returns dict keyed by username with values dict email, phone, full_name

def load_users():
    users = {}
    try:
        with open(os.path.join(DATA_DIR, 'users.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    username, email, phone, full_name = parts
                    users[username] = {
                        'username': username,
                        'email': email,
                        'phone': phone,
                        'full_name': full_name
                    }
    except FileNotFoundError:
        pass
    return users

# Load menu from menu.txt
# returns list of dict dish_id(int), name(str), category(str), price(float), description(str)
def load_menu():
    menu = []
    try:
        with open(os.path.join(DATA_DIR, 'menu.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) >= 8:
                    dish_id = int(parts[0])
                    name = parts[1]
                    category = parts[2]
                    price = float(parts[3])
                    description = parts[4]
                    # other fields ignored for now
                    menu.append({
                        'dish_id': dish_id,
                        'name': name,
                        'category': category,
                        'price': price,
                        'description': description
                    })
    except FileNotFoundError:
        pass
    return menu

# Load reservations from reservations.txt
# returns list of dict reservation_id(int), username(str), guest_name(str), phone(str), email(str), party_size(int), date(str), time(str), special_requests(str), status(str)
def load_reservations():
    reservations = []
    try:
        with open(os.path.join(DATA_DIR, 'reservations.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 10:
                    reservation_id = int(parts[0])
                    username = parts[1]
                    guest_name = parts[2]
                    phone = parts[3]
                    email = parts[4]
                    try:
                        party_size = int(parts[5])
                    except ValueError:
                        party_size = 1
                    date = parts[6]
                    time_ = parts[7]
                    special_requests = parts[8]
                    status = parts[9]
                    reservations.append({
                        'reservation_id': reservation_id,
                        'username': username,
                        'guest_name': guest_name,
                        'phone': phone,
                        'email': email,
                        'party_size': party_size,
                        'date': date,
                        'time': time_,
                        'special_requests': special_requests,
                        'status': status
                    })
    except FileNotFoundError:
        pass
    return reservations

# Load waitlist from waitlist.txt
# returns list of dict waitlist_id(int), username(str), party_size(int), join_time(str), status(str)
def load_waitlist():
    waitlist = []
    try:
        with open(os.path.join(DATA_DIR, 'waitlist.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 5:
                    waitlist_id = int(parts[0])
                    username = parts[1]
                    try:
                        party_size = int(parts[2])
                    except ValueError:
                        party_size = 1
                    join_time = parts[3]
                    status = parts[4]
                    waitlist.append({
                        'waitlist_id': waitlist_id,
                        'username': username,
                        'party_size': party_size,
                        'join_time': join_time,
                        'status': status
                    })
    except FileNotFoundError:
        pass
    return waitlist

# Load reviews from reviews.txt
# returns list of dict review_id(int), username(str), dish_id(int), rating(int), review_text(str), review_date(str)
def load_reviews():
    reviews = []
