# Helper to save users list to file

def save_users(users):
    try:
        with open(os.path.join(DATA_DIR, 'users.txt'), 'w', encoding='utf-8') as f:
            for u in users.values():
                line = f"{u['username']}|{u['email']}|{u['phone']}|{u['full_name']}\n"
                f.write(line)
    except Exception:
        pass

# Utility to get next id based on existing list of dict with id_key

def get_next_id(items, id_key):
    if not items:
        return 1
    else:
        return max(item[id_key] for item in items) + 1

