    user_waitlist_active = False
    position = None
    sorted_waitlist = sorted([w for w in waitlist if w['status'] == 'Active'], key=lambda w: w['join_time'])

    for idx, entry in enumerate(sorted_waitlist, start=1):
        if entry['username'] == username:
            user_waitlist_active = True
            position = idx
            break

    if request.method == 'POST':
        party_size_raw = request.form.get('party_size', '1')
        try:
            party_size = int(party_size_raw)
            if party_size < 1:
                party_size = 1
        except ValueError:
            party_size = 1

        if not user_waitlist_active and username:
            # Add user to waitlist
            next_id = get_next_id(waitlist, 'waitlist_id')
            join_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
