from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Utility functions for loading data from text files

def load_articles():
    articles = []
    path = os.path.join(DATA_DIR, 'articles.txt')
    try:
        with open(path, 'r', encoding='utf-8') as file:
            for line in file:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 7:
                    continue
                article_id, title, author, category, content, date, views = parts
                # Convert types
                try:
                    articles.append({
                        'article_id': int(article_id),
                        'title': title,
                        'author': author,
                        'category': category,
                        'content': content,
                        'date': date,
                        'views': int(views)
                    })
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return articles


def load_categories():
    categories = []
    path = os.path.join(DATA_DIR, 'categories.txt')
    try:
        with open(path, 'r', encoding='utf-8') as file:
            for line in file:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 3:
                    continue
                category_id, category_name, description = parts
                try:
                    categories.append({
                        'category_id': int(category_id),
                        'category_name': category_name
                    })
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return categories


def load_bookmarks():
    bookmarks = []
    path = os.path.join(DATA_DIR, 'bookmarks.txt')
    try:
        with open(path, 'r', encoding='utf-8') as file:
            for line in file:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 4:
                    continue
                bookmark_id, article_id, article_title, bookmarked_date = parts
                try:
                    bookmarks.append({
                        'bookmark_id': int(bookmark_id),
                        'article_id': int(article_id),
                        'article_title': article_title,
                        'bookmarked_date': bookmarked_date
                    })
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return bookmarks


def save_bookmarks(bookmarks):
    path = os.path.join(DATA_DIR, 'bookmarks.txt')
    with open(path, 'w', encoding='utf-8') as file:
        for b in bookmarks:
            line = f"{b['bookmark_id']}|{b['article_id']}|{b['article_title']}|{b['bookmarked_date']}\n"
            file.write(line)


def load_comments():
    comments = []
    path = os.path.join(DATA_DIR, 'comments.txt')
    try:
        with open(path, 'r', encoding='utf-8') as file:
            for line in file:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                comment_id, article_id, article_title, commenter_name, comment_text, comment_date = parts
                try:
                    comments.append({
                        'comment_id': int(comment_id),
                        'article_id': int(article_id),
                        'article_title': article_title,
                        'commenter_name': commenter_name,
                        'comment_text': comment_text,
                        'comment_date': comment_date
                    })
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return comments


def save_comments(comments):
    path = os.path.join(DATA_DIR, 'comments.txt')
    with open(path, 'w', encoding='utf-8') as file:
        for c in comments:
            line = f"{c['comment_id']}|{c['article_id']}|{c['article_title']}|{c['commenter_name']}|{c['comment_text']}|{c['comment_date']}\n"
            file.write(line)


def load_trending():
    trending = []
    path = os.path.join(DATA_DIR, 'trending.txt')
    try:
        with open(path, 'r', encoding='utf-8') as file:
            for line in file:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 5:
                    continue
                article_id, article_title, category, view_count, period = parts
                try:
                    trending.append({
                        'article_id': int(article_id),
                        'title': article_title,
                        'category': category,
                        'view_count': int(view_count),
                        'period': period
                    })
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return trending


# Route implementations
@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard_page'))


@app.route('/dashboard')
def dashboard_page():
    articles = load_articles()
    trending = load_trending()

    # Featured articles: let's consider top 5 by views descending
    featured_articles_sorted = sorted(articles, key=lambda x: x['views'], reverse=True)[:5]
    featured_articles = [{
        'article_id': a['article_id'],
        'title': a['title'],
        'author': a['author'],
        'date': a['date']
    } for a in featured_articles_sorted]

    # Trending articles: use trending data, simplified to article_id and title only
    trending_articles = [{
        'article_id': t['article_id'],
        'title': t['title']
    } for t in trending]

    return render_template('dashboard.html', featured_articles=featured_articles, trending_articles=trending_articles)


