                    if not existing:
                        # Save new location
                        try:
                            # Find max saved_id
                            max_id = max((s['saved_id'] for s in saved_locations_all), default=0)
                            with open(SAVED_LOCATIONS_FILE, 'a', encoding='utf-8') as f:
                                new_line = f"{max_id + 1}|{user_id}|{loc['location_id']}|{loc['location_name']}|0\n"
                                f.write(new_line)
                        except Exception:
